from pathlib import Path
import re, hashlib
root=Path('shaders/cellular_and_stochastic')
files=sorted(root.glob('*/*.frag'))
funcs={}
for p in files:
    text=p.read_text(errors='ignore')
    names=re.findall(r'\b(?:float|vec[234]|int|bool|mat[234]|void)\s+(\w+)\s*\(', text)
    for n in names:
        funcs.setdefault(n, []).append(str(p))
print('repeated function names:')
for n, ps in sorted(funcs.items()):
    if len(ps)>1:
        print(f'{n}: {len(ps)}')
        for p in ps:
            print('  ', p)
# hash non-comment function-ish snippets? also list repeated line count
line_map={}
for p in files:
    for line in p.read_text(errors='ignore').splitlines():
        s=line.strip()
        if not s or s.startswith('//') or s.startswith('#') or s.startswith('uniform '):
            continue
        line_map.setdefault(s,set()).add(str(p))
repeats=[(s,ps) for s,ps in line_map.items() if len(ps)>=3]
print(f'repeated nontrivial lines across >=3 files: {len(repeats)}')
for s,ps in repeats[:20]:
    print(len(ps), s[:120])
PY

